// ── PARTICLE CANVAS ───────────────────────────────────────────────────────
function ParticleField() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    let W, H, particles, animId;
    const N = 120;

    function resize() { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; }

    function init() {
      resize();
      particles = Array.from({ length: N }, () => ({
        x: Math.random() * W, y: Math.random() * H,
        r: Math.random() * 1.8 + 0.3,
        vx: (Math.random() - 0.5) * 0.3,
        vy: (Math.random() - 0.5) * 0.3,
        hue: Math.random() > 0.5 ? 200 : 280,
        alpha: Math.random() * 0.6 + 0.2,
      }));
    }

    function draw() {
      ctx.clearRect(0, 0, W, H);
      // nebula blobs
      [[W*0.15,H*0.3,350,"rgba(120,40,220,0.07)"],[W*0.8,H*0.6,420,"rgba(0,160,255,0.06)"],[W*0.5,H*0.85,300,"rgba(100,20,180,0.05)"]].forEach(([x,y,r,c])=>{
        const g=ctx.createRadialGradient(x,y,0,x,y,r);g.addColorStop(0,c);g.addColorStop(1,"transparent");
        ctx.fillStyle=g;ctx.fillRect(0,0,W,H);
      });
      // connections
      for(let i=0;i<particles.length;i++) for(let j=i+1;j<particles.length;j++){
        const dx=particles[i].x-particles[j].x,dy=particles[i].y-particles[j].y,d=Math.sqrt(dx*dx+dy*dy);
        if(d<110){ctx.beginPath();ctx.moveTo(particles[i].x,particles[i].y);ctx.lineTo(particles[j].x,particles[j].y);
          ctx.strokeStyle=`rgba(100,80,255,${(1-d/110)*0.2})`;ctx.lineWidth=0.5;ctx.stroke();}
      }
      // particles
      particles.forEach(p=>{
        ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
        ctx.fillStyle=`hsla(${p.hue},90%,70%,${p.alpha})`;ctx.fill();
        const g=ctx.createRadialGradient(p.x,p.y,0,p.x,p.y,p.r*7);
        g.addColorStop(0,`hsla(${p.hue},90%,70%,${p.alpha*0.35})`);g.addColorStop(1,"transparent");
        ctx.fillStyle=g;ctx.beginPath();ctx.arc(p.x,p.y,p.r*7,0,Math.PI*2);ctx.fill();
        p.x+=p.vx;p.y+=p.vy;
        if(p.x<0)p.x=W;if(p.x>W)p.x=0;if(p.y<0)p.y=H;if(p.y>H)p.y=0;
      });
      animId=requestAnimationFrame(draw);
    }
    init(); draw();
    window.addEventListener("resize", resize);
    return ()=>{cancelAnimationFrame(animId);window.removeEventListener("resize",resize);};
  },[]);
  return <canvas ref={canvasRef} style={{position:"fixed",inset:0,zIndex:0,pointerEvents:"none"}}/>;
}

// ── CUSTOM CURSOR ─────────────────────────────────────────────────────────
function CustomCursor() {
  const dotRef  = useRef(null);
  const ringRef = useRef(null);
  const pos     = useRef({x:0,y:0});
  const ring    = useRef({x:0,y:0});
  const [trails, setTrails] = useState(Array.from({length:8},()=>({x:0,y:0})));
  const trailPos = useRef(Array.from({length:8},()=>({x:0,y:0})));

  useEffect(()=>{
    const mv=e=>{
      pos.current={x:e.clientX,y:e.clientY};
      if(dotRef.current){dotRef.current.style.left=e.clientX+"px";dotRef.current.style.top=e.clientY+"px";}
    };
    let animId;
    const tick=()=>{
      ring.current.x+=(pos.current.x-ring.current.x)*0.12;
      ring.current.y+=(pos.current.y-ring.current.y)*0.12;
      if(ringRef.current){ringRef.current.style.left=ring.current.x+"px";ringRef.current.style.top=ring.current.y+"px";}
      const arr = trailPos.current;
      for(let i=arr.length-1;i>0;i--){arr[i].x+=(arr[i-1].x-arr[i].x)*0.35;arr[i].y+=(arr[i-1].y-arr[i].y)*0.35;}
      arr[0].x+=(pos.current.x-arr[0].x)*0.5;arr[0].y+=(pos.current.y-arr[0].y)*0.5;
      setTrails(arr.map(p=>({x:p.x,y:p.y})));
      animId=requestAnimationFrame(tick);
    };
    window.addEventListener("mousemove",mv);
    animId=requestAnimationFrame(tick);
    return()=>{window.removeEventListener("mousemove",mv);cancelAnimationFrame(animId);};
  },[]);

  return <>
    {trails.map((t,i)=>(
      <div key={i} style={{position:"fixed",width:"5px",height:"5px",borderRadius:"50%",
        background:`rgba(0,195,255,${0.55-i*0.06})`,pointerEvents:"none",zIndex:9999,
        left:t.x,top:t.y,transform:"translate(-50%,-50%)",transition:"none"}}/>
    ))}
    <div ref={dotRef}  style={{position:"fixed",width:"8px",height:"8px",borderRadius:"50%",background:"#00c3ff",pointerEvents:"none",zIndex:9999,transform:"translate(-50%,-50%)",boxShadow:"0 0 12px #00c3ff"}}/>
    <div ref={ringRef} style={{position:"fixed",width:"32px",height:"32px",borderRadius:"50%",border:"1px solid #a855f788",pointerEvents:"none",zIndex:9999,transform:"translate(-50%,-50%)"}}/>
  </>;
}


// ── 3D TILT CARD ──────────────────────────────────────────────────────────
function TiltCard({children,style={}}) {
  const ref=useRef(null);
  const mv=e=>{
    const r=ref.current.getBoundingClientRect();
    const x=(e.clientX-r.left)/r.width-0.5,y=(e.clientY-r.top)/r.height-0.5;
    ref.current.style.transform=`perspective(900px) rotateY(${x*16}deg) rotateX(${-y*12}deg) scale(1.025)`;
    ref.current.style.boxShadow=`${-x*24}px ${y*24}px 60px rgba(100,60,255,0.22),0 0 40px rgba(0,195,255,0.08)`;
  };
  const ml=()=>{ref.current.style.transform="perspective(900px) rotateY(0) rotateX(0) scale(1)";ref.current.style.boxShadow="none";};
  return <div ref={ref} onMouseMove={mv} onMouseLeave={ml} style={{transition:"transform .15s ease,box-shadow .15s ease",...style}}>{children}</div>;
}

// ── HOLO TEXT ─────────────────────────────────────────────────────────────
function HoloText({children,size="72px",tag="h2"}) {
  const Tag=tag;
  return <Tag style={{fontFamily:"'Orbitron',sans-serif",fontSize:size,fontWeight:900,background:`linear-gradient(135deg,#fff 0%,${T.blue} 40%,${T.purple} 70%,#fff 100%)`,backgroundSize:"200% 200%",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundClip:"text",animation:"holoShift 4s ease infinite",letterSpacing:"0.04em",lineHeight:1}}>{children}</Tag>;
}

// ── LABEL ─────────────────────────────────────────────────────────────────
function Label({text}) {
  return <p style={{fontFamily:"'Orbitron',sans-serif",fontSize:"10px",letterSpacing:"0.4em",color:T.blue,textTransform:"uppercase",marginBottom:"16px",opacity:.8}}>◈ {text}</p>;
}

// ── NAV ───────────────────────────────────────────────────────────────────
function Nav({active}) {
  const links=["home","about","projects","skills","contact"];
  const go=id=>document.getElementById(id)?.scrollIntoView({behavior:"smooth"});
  const isMobile = useIsMobile();
  return (
    <nav style={{position:"fixed",top:"16px",left:"50%",transform:"translateX(-50%)",zIndex:200,display:"flex",gap:"2px",background:"rgba(10,6,30,0.85)",border:`1px solid ${T.border}`,backdropFilter:"blur(20px)",borderRadius:"60px",padding:"4px",maxWidth:"95vw"}}>
      {links.map(l=>(
        <button key={l} onClick={()=>go(l)} style={{padding:isMobile?"6px 12px":"8px 24px",borderRadius:"50px",border:"none",background:active===l?`linear-gradient(135deg,${T.violet},${T.blue})`:"transparent",color:active===l?T.white:T.muted,fontFamily:"'Orbitron',sans-serif",fontSize:isMobile?"8px":"10px",letterSpacing:isMobile?"0.05em":"0.15em",textTransform:"uppercase",cursor:"pointer",transition:"all .3s",boxShadow:active===l?`0 0 20px ${T.blueGlow}`:"none"}}>
          {l}
        </button>
      ))}
    </nav>
  );
}

